import '@testing-library/jest-dom';
// This file was generated by an AI agent. Do not edit directly.
import * as React from 'react';
import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { MagnifyingGlassIcon, CheckIcon } from '@radix-ui/react-icons';
import { Input } from './Input';

describe('Input rendering', () => {
  it('renders a textbox with the provided label', () => {
    render(<Input label="Email" />);
    expect(screen.getByRole('textbox', { name: /email/i })).toBeInTheDocument();
  });

  it('derives the accessible name from ariaLabel when label is missing', () => {
    render(<Input ariaLabel="Secondary email" />);
    expect(screen.getByRole('textbox', { name: /secondary email/i })).toBeInTheDocument();
  });

  it('prefers the visible label when both label and ariaLabel are provided', () => {
    render(<Input label="Primary email" ariaLabel="Secondary" />);
    expect(screen.getByRole('textbox', { name: /primary email/i })).toBeInTheDocument();
  });

  it('renders with an empty accessible name when neither label nor ariaLabel is provided', () => {
    render(<Input />);
    const input = screen.getByRole('textbox');
    expect(input).toHaveAccessibleName('');
  });
});

describe('Input native attribute passthrough', () => {
  it('forwards placeholder to the native input', () => {
    render(<Input label="Email" placeholder="name@example.com" />);
    const input = screen.getByRole('textbox', { name: /email/i });
    expect(input).toHaveAttribute('placeholder', 'name@example.com');
  });

  it('marks the native input as required when requested', () => {
    render(<Input label="Email" required />);
    const input = screen.getByRole('textbox', { name: /email/i });
    expect(input).toBeRequired();
  });

  it('merges user-provided aria-describedby with internal ids', async () => {
    const user = userEvent.setup();
    render(<Input label="Email" info="Info text" aria-describedby="external-id" />);
    const trigger = screen.getByRole('button', { name: /more info/i });
    await user.click(trigger);
    const input = screen.getByRole('textbox', { name: /email/i });
    const describedBy = input.getAttribute('aria-describedby') ?? '';
    expect(describedBy).toContain('external-id');
  });
});

describe('Input info popover', () => {
  it('renders the info trigger button when info text is present', () => {
    render(<Input label="Email" info="We will contact you at this email." />);
    expect(screen.getByRole('button', { name: /more info/i })).toBeInTheDocument();
  });

  it('adds the info content id to aria-describedby after opening the popover', async () => {
    const user = userEvent.setup();
    render(<Input label="Email" info="We will contact you at this email." />);
    const trigger = screen.getByRole('button', { name: /more info/i });
    await user.click(trigger);
    const content = await screen.findByText('We will contact you at this email.');
    const input = screen.getByRole('textbox', { name: /email/i });
    expect(input.getAttribute('aria-describedby') ?? '').toContain(content.id);
  });
});

describe('Input messaging', () => {
  it('omits the hint slot when an error is provided', () => {
    render(<Input label="Email" hint="Helpful hint" error="This field is required." />);
    expect(document.querySelector('[data-slot="hint"]')).toBeNull();
  });

  it('links aria-describedby to the error message when present', () => {
    render(<Input label="Email" error="This field is required." />);
    const input = screen.getByRole('textbox', { name: /email/i });
    const errorElement = document.querySelector('[data-slot="error"]') as HTMLElement;
    expect(input.getAttribute('aria-describedby')).toBe(errorElement.id);
  });

  it('sets the invalid state on the root so the input row gets the danger border via state selector', () => {
    render(<Input label="Email" error="This field is required." />);
    const group = screen.getByRole('group');
    expect(group).toHaveAttribute('data-invalid', 'true');
  });
});

describe('Input disabled state', () => {
  it('disables the fieldset when disabled is true', () => {
    render(<Input label="Email" disabled />);
    const group = screen.getByRole('group');
    expect(group).toBeDisabled();
  });

  it('disables the native input when disabled is true', () => {
    render(<Input label="Email" disabled />);
    expect(screen.getByRole('textbox', { name: /email/i })).toBeDisabled();
  });
});

describe('Input icons', () => {
  it('marks the start icon wrapper as aria-hidden', () => {
    render(<Input label="Search" startIcon={<MagnifyingGlassIcon aria-hidden="true" />} />);
    const wrapper = document.querySelector('[data-slot="startIcon"]') as HTMLElement;
    expect(wrapper.getAttribute('aria-hidden')).toBe('true');
  });

  it('marks the end icon wrapper as aria-hidden', () => {
    render(<Input label="Search" endIcon={<CheckIcon aria-hidden="true" />} />);
    const wrapper = document.querySelector('[data-slot="endIcon"]') as HTMLElement;
    expect(wrapper.getAttribute('aria-hidden')).toBe('true');
  });
});

describe('Input a11y structure', () => {
  it('does not apply aria-describedby to the fieldset root', () => {
    render(<Input label="Email" hint="Helpful hint" />);
    const group = screen.getByRole('group');
    expect(group).not.toHaveAttribute('aria-describedby');
  });
});

